insert into backlog_meta (id, meta, personas) values (1, '{"product": "climbwork / cliff_ios", "generated": "2026-06-25", "source": "memo-2026-06-25", "goalPriority": ["retention", "monetization"], "iceScale": "1-10 each; iceScore(feature) = maxPersonaImpact x confidence x ease", "note": "1차: 메모 소스만 반영. 이후 나머지 메모 + 스프레드시트/노션/지라 추가 예정.", "categories": {"new": "✨ 완전 새로운 기능", "cliff_ios": "📱 cliff_ios · UI/UX 개선", "climbpipekit": "⚙️ ClimbPipeKit · 모델·알고리즘 개선", "gtm": "🚀 GTM·운영"}}'::jsonb, '[{"id": "P1", "name": "공유러", "desc": "SNS에 등반 클립을 올리는 사람. 빠르고 멋진 하이라이트·크롭·필터·시각효과 영상이 핵심. 리텐션 훅 = 올릴 거리가 계속 생김."}, {"id": "P2", "name": "성장러", "desc": "기록으로 실력을 늘리려는 사람. 등반 복기·메모·루트 기록·진척 추적이 핵심. 리텐션 훅 = 성장·습관이 눈에 보임."}]'::jsonb)
insert into backlog_ideas (id, ord, category, type, status, ice, data) values
  ('IDEA-001', 1, 'new', 'feature', 'todo', 560, '{"id": "IDEA-001", "category": "new", "title": "스타트/탑홀드 선택 — 다목적 기반 기능", "type": "feature", "theme": "logging", "source": ["memo", "jira:CRUXCUT-41", "jira:CRUXCUT-57"], "userPriority": 4, "goalFit": "retention", "children": [{"title": "① 등반 구간 자동 컷편집", "userStory": {"as": "클라이머", "want": "삼각대로 길게 녹화해도 출발·완등이 자동 인식돼 실제 등반 구간만 잘림", "soThat": "번거로운 수동 컷편집 없이 등반 부분만 바로 얻는다"}, "problem": "문제를 풀 때까지 삼각대를 고정해 계속 녹화하면, 나중에 실제 등반한 부분만 잘라내는 컷편집이 번거로움", "alternatives": "긴 영상을 수동으로 트림/컷편집"}, {"title": "② 시도별 운동/휴식 시간 트래킹", "userStory": {"as": "성장러", "want": "문제 시도별 운동시간·휴식시간이 자동 기록", "soThat": "트라이/휴식 패턴을 운동 데이터로 복기한다"}, "problem": "세션의 시도·휴식 시간을 수동으로 남기기 번거로워 운동 데이터가 안 쌓임", "alternatives": "스톱워치로 수동 측정"}, {"title": "③ 등반자 특정 (여러 명일 때)", "userStory": {"as": "공유러", "want": "화면에 여러 명이 있어도 내 스타트홀드를 지정해 등반자를 특정하도록", "soThat": "들찍이 엉뚱한 사람을 잡지 않고 내 등반만 추적된다"}, "problem": "화면에 클라이머가 여러 명일 때(들찍 실패의 가장 흔한 케이스) 엉뚱한 사람을 추적", "alternatives": "혼자 있을 때만 촬영", "note": "여러 명 중 내 스타트홀드를 지정해 특정 (구 IDEA-008 멀티클라이머 선택을 흡수)."}, {"title": "④ 포즈 감지 백업 (리드에서 멀어 안 보일 때)", "note": "리드에서 클라이머가 멀리 올라가 작아지면 포즈 모델이 감지를 놓치는데, 지정한 스타트→탑 홀드 경로가 있으면 그 위치로 추적을 백업할 수 있음(감지 실패 구간 보완)."}, {"title": "⑤ 긴 리드 영상 성능 최적화 (stride 확대)", "note": "스타트→탑 경로가 미리 있으면 추적이 경로를 따라가면 되므로, 길이가 긴 리드 영상에서 프레임 stride를 더 크게 키워 처리 속도를 높일 수 있음(트래킹 stride 활용)."}], "personaImpact": {"P1": 8, "P2": 10}, "confidence": 8, "ease": 7, "iceScore": 560, "implementation": {"reuse": "추적/감지, 기록 탭, 스타트→탑 홀드 경로", "new": "스타트/탑홀드 선택 UI, 선택 기반 출발·완등 판정, 자동 구간 분리, 시도별 타이머·휴식 분석", "synergy": "등반자 특정 use case 포함(구 IDEA-008 흡수), 수동 컷 편집(IDEA-007), 운동기록(IDEA-003)"}, "notes": "스타트/탑홀드 선택은 출발·완등 인식의 구현 방식이자 여러 use case의 기반(등반자 특정(구 IDEA-008 흡수)·포즈 백업·성능). 메모 !!!! 최상위. Ease 7은 핵심(홀드 선택+판정) 기준; ③④는 경로가 있으면 대체로 따라오는 이득."}'::jsonb),
