  ('IDEA-003', 3, 'new', 'feature', 'todo', 280, '{"id": "IDEA-003", "category": "new", "title": "운동기록 트래킹(체중·난이도수·높이·시도횟수)", "type": "feature", "theme": "logging", "source": ["memo"], "userPriority": 0, "goalFit": "both", "userStory": {"as": "성장러", "want": "체중·완등 난이도수·올라간 높이·시도횟수를 기록", "soThat": "운동 앱으로서 내 진척을 데이터로 본다"}, "problem": "등반을 운동으로 정량 추적할 수단이 없음", "alternatives": "별도 운동기록 앱·노트", "personaImpact": {"P1": 1, "P2": 8}, "confidence": 7, "ease": 5, "iceScore": 280, "implementation": {"reuse": "기록 탭, 자동인식(IDEA-002)", "new": "기록 데이터모델, 시도횟수 카운트 UI", "synergy": "맞춤추천(IDEA-022)·streaks(IDEA-020)·위젯(IDEA-023)의 데이터원"}}'::jsonb),
  ('IDEA-004', 4, 'cliff_ios', 'feature', 'todo', 168, '{"id": "IDEA-004", "category": "cliff_ios", "title": "크롭을 메타데이터 기반 실시간 뷰로 (실제 크롭은 공유 시에만)", "type": "feature", "theme": "crop", "source": ["memo"], "userPriority": 0, "goalFit": "foundational", "userStory": {"as": "공유러", "want": "크롭 비율·크기를 바꾸면 전체영상+클라이머 경로+크롭 정보로 결과 화면에서 즉시 렌더되고, 실제 크롭 영상은 공유할 때만 생성되도록", "soThat": "비율을 자유롭게 바꿔보면서도 처리시간·저장공간을 아낀다"}, "problem": "crop이 파이프라인 병목인데, 크롭 비율/크기를 바꿀 때마다 영상을 다시 인코딩하는 게 비효율", "alternatives": "바꿀 때마다 crop 재렌더(느림), 또는 비율별로 미리 저장(저장공간 낭비)", "personaImpact": {"P1": 6, "P2": 3}, "confidence": 7, "ease": 4, "iceScore": 168, "implementation": {"reuse": "crop 경로/CoG, 재생 뷰", "new": "메타데이터 기반 실시간 크롭 뷰포트 렌더, export 시에만 crop() 머티리얼라이즈(지연 크롭)", "synergy": "크롭비율 자유형(IDEA-006), trim(IDEA-005)"}, "notes": "extract→crop→slice 파이프라인 구조 최적화. frozen crop() API와의 관계 검토 필요(현재 crop은 즉시 렌더). 코어 파이프라인을 건드리므로 ClimbPipeKit 카테고리로 옮길지 검토 가능."}'::jsonb),
  ('IDEA-005', 5, 'cliff_ios', 'feature', 'todo', 336, '{"id": "IDEA-005", "category": "cliff_ios", "title": "영상 업로드 앞뒤 구간 조정(trim, 필요구간만 처리)", "type": "feature", "theme": "export", "source": ["memo"], "userPriority": 1, "goalFit": "foundational", "userStory": {"as": "클라이머", "want": "업로드 영상의 앞뒤 불필요 구간을 자른 뒤 처리", "soThat": "필요한 구간만 처리해 빠르고 깔끔하다"}, "problem": "전체 영상을 다 처리해 느리고 불필요 구간이 섞이면서 트래킹 퀄리티 떨어짐", "alternatives": "원본 그대로 처리", "personaImpact": {"P1": 5, "P2": 7}, "confidence": 8, "ease": 6, "iceScore": 336, "implementation": {"reuse": "AVFoundation trim", "new": "앞뒤 구간 조정 UI → 처리 범위 전달", "synergy": "처리 성능(IDEA-036 계열)"}, "status": "todo", "notes": ""}'::jsonb),
